DROP TABLE IF EXISTS `game`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `game` (
  `id` bigint(10) unsigned NOT NULL AUTO_INCREMENT,
  `championship_id` bigint(10) unsigned NOT NULL,
  `game_type_id` bigint(10) unsigned NOT NULL,
  `home_team_id` bigint(10) unsigned NOT NULL,
  `away_team_id` bigint(10) unsigned NOT NULL,
  `num_home_team_goals` smallint(5) unsigned DEFAULT NULL,
  `num_away_team_goals` smallint(5) unsigned DEFAULT NULL,
  `num_home_team_extra_goals` smallint(5) unsigned DEFAULT NULL,
  `num_away_team_extra_goals` smallint(5) unsigned DEFAULT NULL,
  `num_home_team_pnt_goals` smallint(5) unsigned DEFAULT NULL,
  `num_away_team_pnt_goals` smallint(5) unsigned DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `id_unique` (`id`),
  KEY `fk_game_team_a` (`home_team_id`),
  KEY `fk_game_team_b` (`away_team_id`),
  KEY `fk_game_championship` (`championship_id`),
  KEY `fk_game_game_type` (`game_type_id`),
  CONSTRAINT `fk_game_championship` FOREIGN KEY (`championship_id`) REFERENCES `championship` (`id`),
  CONSTRAINT `fk_game_game_type` FOREIGN KEY (`game_type_id`) REFERENCES `game_type` (`id`),
  CONSTRAINT `fk_game_team_a` FOREIGN KEY (`home_team_id`) REFERENCES `team` (`id`),
  CONSTRAINT `fk_game_team_b` FOREIGN KEY (`away_team_id`) REFERENCES `team` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2062 DEFAULT CHARSET=latin1;
